exercises.starter:
function weightedRandom(servers) {
  // return a function () => server id
  // Example: [{id:'a',weight:1},{id:'b',weight:3}] → 'b' picked ~75% of the time
}

exercises.tests:
check('always picks valid server', () => {
  const n = weightedRandom([{id:'a',weight:1},{id:'b',weight:3}]);
  const ids = new Set(['a','b']);
  for (let i = 0; i < 100; i++) expect(ids.has(n())).toBe(true);
});
check('single server always returned', () => {
  const n = weightedRandom([{id:'only',weight:5}]);
  expect(n()).toBe('only');
});
check('zero-weight server never picked', () => {
  const n = weightedRandom([{id:'a',weight:0},{id:'b',weight:1}]);
  for (let i = 0; i < 50; i++) expect(n()).toBe('b');
});

exercises.solution:
function weightedRandom(servers) {
  const total = servers.reduce((s, x) => s + x.weight, 0);
  return () => {
    let r = Math.random() * total;
    for (const s of servers) {
      r -= s.weight;
      if (r <= 0) return s.id;
    }
    return servers[servers.length - 1].id;
  };
}

exercises.starter:
function LRUCache(capacity) {
  // attach get(key) and put(key, value) methods
  this.get = function(key) {};
  this.put = function(key, value) {};
}

exercises.tests:
check('basic get/put', () => {
  const c = new LRUCache(2);
  c.put(1, 1); c.put(2, 2);
  expect(c.get(1)).toBe(1);
  c.put(3, 3);
  expect(c.get(2)).toBe(-1);
});
check('update existing', () => {
  const c = new LRUCache(2);
  c.put(1, 10); c.put(1, 20);
  expect(c.get(1)).toBe(20);
});
check('miss returns -1', () => {
  const c = new LRUCache(1);
  expect(c.get(99)).toBe(-1);
});
check('capacity 1 evicts old on new insert', () => {
  const c = new LRUCache(1);
  c.put(1, 1); c.put(2, 2);
  expect(c.get(1)).toBe(-1);
  expect(c.get(2)).toBe(2);
});

exercises.solution:
function LRUCache(capacity) {
  const map = new Map();
  this.get = function(key) {
    if (!map.has(key)) return -1;
    const val = map.get(key);
    map.delete(key); map.set(key, val);
    return val;
  };
  this.put = function(key, value) {
    if (map.has(key)) map.delete(key);
    map.set(key, value);
    if (map.size > capacity) map.delete(map.keys().next().value);
  };
}

exercises.starter:
// hash(str) is provided — returns a non-negative integer
function consistentHash(servers, replicas) {
  // Build the ring, return { lookup(key) }
  return {
    lookup(key) {}
  };
}

exercises.tests:
check('returns a known server', () => {
  const ring = consistentHash(['A','B','C'], 10);
  const result = ring.lookup('my-key');
  expect(['A','B','C'].includes(result)).toBe(true);
});
check('same key always same server', () => {
  const ring = consistentHash(['A','B','C'], 10);
  expect(ring.lookup('stable')).toBe(ring.lookup('stable'));
});
check('works with one server', () => {
  const ring = consistentHash(['only'], 5);
  expect(ring.lookup('anything')).toBe('only');
});

exercises.solution:
function consistentHash(servers, replicas) {
  const ring = [];
  for (const s of servers) {
    for (let r = 0; r < replicas; r++) {
      ring.push({ pos: hash(s + '#' + r), server: s });
    }
  }
  ring.sort((a, b) => a.pos - b.pos);
  return {
    lookup(key) {
      const h = hash(key);
      for (const node of ring) if (node.pos >= h) return node.server;
      return ring[0].server;
    }
  };
}

exercises.starter:
function dedupeSet(windowMs) {
  // return { seen(key): boolean }
  return {
    seen(key) {}
  };
}

exercises.tests:
check('first call not duplicate', () => {
  const d = dedupeSet(1000);
  expect(d.seen('k1')).toBe(false);
});
check('second call is duplicate', () => {
  const d = dedupeSet(1000);
  d.seen('k1');
  expect(d.seen('k1')).toBe(true);
});
check('different keys independent', () => {
  const d = dedupeSet(1000);
  d.seen('a');
  expect(d.seen('b')).toBe(false);
});
check('expired key is fresh', () => {
  const d = dedupeSet(0);
  d.seen('x');
  expect(d.seen('x')).toBe(false);
});

exercises.solution:
function dedupeSet(windowMs) {
  const store = new Map();
  return {
    seen(key) {
      const now = Date.now();
      const ts = store.get(key);
      if (ts !== undefined && now - ts < windowMs) return true;
      store.set(key, now);
      return false;
    }
  };
}

exercises.starter:
function tokenBucket(capacity, refillPerSecond) {
  // return { consume(tokens): boolean }
  return {
    consume(tokens) {}
  };
}

exercises.tests:
check('full bucket allows consume', () => {
  const b = tokenBucket(10, 1);
  expect(b.consume(5)).toBe(true);
});
check('exceeded capacity returns false', () => {
  const b = tokenBucket(3, 1);
  expect(b.consume(5)).toBe(false);
});
check('consuming all then one more fails', () => {
  const b = tokenBucket(2, 0);
  b.consume(2);
  expect(b.consume(1)).toBe(false);
});
check('consume(0) always true', () => {
  const b = tokenBucket(0, 0);
  expect(b.consume(0)).toBe(true);
});

exercises.solution:
function tokenBucket(capacity, refillPerSecond) {
  let tokens = capacity;
  let last = Date.now();
  return {
    consume(n) {
      const now = Date.now();
      tokens = Math.min(capacity, tokens + (now - last) / 1000 * refillPerSecond);
      last = now;
      if (n <= tokens) { tokens -= n; return true; }
      return false;
    }
  };
}
